parameters.jsCode:
const probe = $input.first().json;
const assetVal = $('Normalize Input').first().json.asset_value;
const assetId = $('Normalize Input').first().json.asset_id;
const engId = $('Normalize Input').first().json.engagement_id;
const scanJobId = $('Create Scan Job').first().json.id;

const headers = probe.headers || {};
const statusCode = probe.statusCode || 0;
const body = (probe.body || '').substring(0, 2000);

// Security header checks
const secHeaders = [
  'strict-transport-security','content-security-policy','x-frame-options',
  'x-content-type-options','referrer-policy','permissions-policy'
];
const missingHeaders = secHeaders.filter(h => !headers[h] && !headers[h.toLowerCase()]);
const presentHeaders = secHeaders.filter(h => headers[h] || headers[h.toLowerCase()]);

// Server version disclosure
const serverHeader = headers['server'] || headers['Server'] || '';
const xPoweredBy = headers['x-powered-by'] || headers['X-Powered-By'] || '';
const versionDisclosure = /\d+\.\d+/.test(serverHeader) || /\d+\.\d+/.test(xPoweredBy);

// Tech detection from headers
const techStack = [];
if (/nginx/i.test(serverHeader)) techStack.push('nginx');
if (/apache/i.test(serverHeader)) techStack.push('apache');
if (/iis/i.test(serverHeader)) techStack.push('IIS');
if (/express/i.test(xPoweredBy)) techStack.push('Express.js');
if (/php/i.test(xPoweredBy)) techStack.push('PHP');
if (/asp\.net/i.test(xPoweredBy)) techStack.push('ASP.NET');
if (/wordpress/i.test(body)) techStack.push('WordPress');

const findings = [];
if (missingHeaders.length > 0) {
  findings.push({ type: 'missing_security_headers', headers: missingHeaders, severity: missingHeaders.includes('content-security-policy') ? 'medium' : 'low' });
}
if (versionDisclosure) {
  findings.push({ type: 'version_disclosure', server: serverHeader, x_powered_by: xPoweredBy, severity: 'informational' });
}

return [{ json: {
  asset_id: assetId,
  asset_value: assetVal,
  engagement_id: engId,
  scan_job_id: scanJobId,
  status_code: statusCode,
  server_header: serverHeader,
  x_powered_by: xPoweredBy,
  tech_stack: techStack,
  missing_security_headers: missingHeaders,
  present_security_headers: presentHeaders,
  version_disclosure: versionDisclosure,
  findings,
  has_findings: findings.length > 0
} }];

const data = $('Analyze Response').first().json;
return data.findings.map(f => ({ json: {
  engagement_id: data.engagement_id,
  asset_id: data.asset_id,
  source_tool: 'recon_http',
  title: f.type === 'missing_security_headers'
    ? `Missing Security Headers: ${f.headers.join(', ')}`
    : 'Server Version Disclosure',
  raw_severity: f.severity,
  raw_evidence: JSON.stringify(f),
  raw_data: f
} }));

